@clementlefevre You want to use the notebook's CodeMirror module vs. importing your own (which is conveniently available as a [global](https://github.com/jupyter/notebook/blob/master/notebook/static/notebook/js/main.js#L83) `CodeMirror`). However, setting `CodeMirror.keyMap.pcDefault["Ctrl-Down"]` in `custom.js` will affect the global `CodeMirror` but none of the instances used by the `Cell` objects in the notebook (because `custom.js` is being executed after the notebook is loaded), so if you want to add this keymap to work in your cells, you will need to get all of the cells and modify their `code_mirror` instances. An example `custom.js`:

```js
// Get instances of `Cell` in the notebook
var cells = $('#notebook-container').find('.cell').map(function() { 
  return $(this).data('cell')
});
// For each instance of `Cell`, add a keymap to `Cell.code_mirror`
cells.each(function(index) {
    this.code_mirror.addKeyMap({
        'Ctrl-Down': function(cm) {
            var current_cursor = cm.doc.getCursor();
            var line_content = cm.doc.getLine(current_cursor.line);
            CodeMirror.commands.goLineEnd(cm);
            CodeMirror.commands.newlineAndIndent(cm);
            cm.doc.replaceSelection(line_content);
            cm.doc.setCursor(current_cursor.line + 1, current_cursor.ch);
        }
    });
});
```

