Actually I have it worked out! There is one line you have to change to ignore finding packages for __main__ (ingredient.py line 284). The following are a minimal demo and the outputs.

```python
import functools, time, os, ipyparallel, pdb, inspect, sys

def test_func(a,b=2,seed=None, *args, **kwargs):
    return locals().copy()

print(('the_original',inspect.getargspec(test_func)))
print(test_func(3,4))
# ('the_original', ArgSpec(args=['a', 'b', 'seed'], varargs='args', keywords='kwargs', defaults=(2, None)))
# {'seed': None, 'args': (), 'kwargs': {}, 'a': 3, 'b': 4}

def partial_but_seed(func, *args_partial, **kw_partial):
    def wrapped_func(seed):
        return func(seed=seed, *args_partial, **kw_partial)
    return wrapped_func

def seeds_map(seeds, mapper=map, collector=list):
    def real_wrapper(func):
        @functools.wraps(func)
        def _seeds_map(*args_map, **kw_map):

            kw_map.pop('seed', 'not to use')
            disk_store = kw_map.pop('disk_store', True)

            rc = mapper(partial_but_seed(func, *args_map, **kw_map), seeds)

            return collector(rc)
        _seeds_map.__signature__ = inspect.signature(func)
        return _seeds_map
    return real_wrapper

plain_wrap = seeds_map(range(2))(test_func)

print(('plain_wrap', inspect.getargspec(plain_wrap)))
print(plain_wrap(a=5, b=6,))
# ('plain_wrap', ArgSpec(args=['a', 'b', 'seed'], varargs='args', keywords='kwargs', defaults=(2, None)))
# [{'seed': 0, 'args': (), 'kwargs': {}, 'a': 5, 'b': 6}, {'seed': 1, 'args': (), 'kwargs': {}, 'a': 5, 'b': 6}]

if __name__ == '__main__':

    from sacred import Experiment
    from sacred.observers.mongo import MongoObserver

    ex = Experiment('demo')
    ex.main(plain_wrap)
    ex.run(dict(a=5,b=6))
    # INFO - demo - Result: [{'kwargs': {}, 'seed': 0, 'a': 5, 'b': 6, 'args': ()}, {'kwargs': {}, 'seed': 1, 'a': 5, 'b': 6, 'args': ()}]

    ex.main(seeds_map(range(2), ipyparallel.Client().load_balanced_view().map)(test_func))
    ex.run(dict(a=7,b=8))
    # INFO - demo - Result: [{'args': (), 'seed': 0, 'a': 7, 'b': 8, 'kwargs': {}}, {'kwargs': {}, 'seed': 1, 'a': 7, 'b': 8, 'args': ()}]
```

@egede I'm not certain I trust that I know which version of `data.py` the user will get. I would assume they'll get the one that we make which is shipped as part of a tarball which is extracted just before the job runs but if they end up with the `data.py` from LHCbDIRAC (if any) then this would confuse things.

I'm not planning to stop users doing this if they want but a 1 line warning that they might be doing things in a sub-optimal way would probably be better imo. It would hopefully stop people accidentally submitting jobs which `worked at CERN` across to different sites on the grid without access to the data.

I don't think there's any guarantee of being able to stream from the locations we extract from eos or elsewhere to all sites is there?

